def ask_ollama(prompt: str, model: str = "llama3:8b") -> str:
    """Interroge Ollama en local. Retourne le texte généré."""
    try:
        import requests as _req
        resp = _req.post(OLLAMA_URL, json={
            "model":  model,
            "prompt": prompt,
            "stream": False,
        }, timeout=60)
        if resp.status_code == 200:
            return resp.json().get("response","").strip()
        return f"Erreur Ollama : HTTP {resp.status_code}"
    except Exception as e:
        return f"Ollama non disponible : {e}. Lancez : ollama serve"
BLOCKED_DB = os.path.join(os.path.dirname(os.path.abspath(__file__)), "blocked_ips.db")

def _init_blocked_db():
    conn = sqlite3.connect(BLOCKED_DB)
    conn.execute("CREATE TABLE IF NOT EXISTS blocked_ips (ip TEXT PRIMARY KEY, blocked_at TEXT)")
    conn.commit(); conn.close()

def db_load_blocked() -> set:
    try:
        _init_blocked_db()
        conn = sqlite3.connect(BLOCKED_DB)
        rows = conn.execute("SELECT ip FROM blocked_ips").fetchall()
        conn.close()
        return {r[0] for r in rows}
    except: return set()

def db_add_blocked(ip: str):
    try:
        _init_blocked_db()
        conn = sqlite3.connect(BLOCKED_DB)
        conn.execute("INSERT OR IGNORE INTO blocked_ips VALUES (?, ?)",
                     (ip, datetime.now().isoformat()))
        conn.commit(); conn.close()
    except Exception as e: pass

def db_remove_blocked(ip: str):
    try:
        conn = sqlite3.connect(BLOCKED_DB)
        conn.execute("DELETE FROM blocked_ips WHERE ip = ?", (ip,))
        conn.commit(); conn.close()
    except: pass
