def make_token(username, role):
    payload = f"{username}:{role}:{int(time.time())}"
    sig = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).hexdigest()[:16]
    return base64.b64encode(f"{payload}:{sig}".encode()).decode()

def verify_token(token):
    try:
        decoded = base64.b64decode(token.encode()).decode()
        payload, sig = decoded.rsplit(":", 1)
        expected = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).hexdigest()[:16]
        if not hmac.compare_digest(sig, expected):
            return None, None
        parts = payload.split(":")
        username, role, ts = parts[0], parts[1], parts[2]
        if int(time.time()) - int(ts) > 28800:   # 8h expiry
            return None, None
        return username, role
    except Exception:
        return None, None

# ================================================================
# CACHE TTL (amélioration #1 — Redis-like sans dépendance)
# ================================================================

_cache: dict = {}
_cache_lock = threading.Lock()

def cache_get(key, ttl=5):
    with _cache_lock:
        e = _cache.get(key)
        if e and (time.time() - e["ts"]) < ttl:
            return e["val"]
    return None

def cache_set(key, val):
    with _cache_lock:
        _cache[key] = {"val": val, "ts": time.time()}

# ================================================================
# GÉOLOCALISATION RÉELLE (amélioration #2 — ip-api.com)
# ================================================================

@st.cache_data(ttl=3600, show_spinner=False)
def geolocate_ips(ips_tuple):
    """Batch géolocalisation via ip-api.com (gratuit, 45 req/min, 100 IP/batch)."""
    ips = [ip for ip in list(ips_tuple) if ip and not str(ip).startswith(("10.","192.168.","172.16.","127."))]
    if not ips:
        return {}
    result = {}
    for batch_start in range(0, len(ips), 100):
        batch = ips[batch_start:batch_start+100]
        try:
            resp = requests.post(
                "http://ip-api.com/batch",
                json=[{"query": ip, "fields": "query,lat,lon,country,city,countryCode,org"} for ip in batch],
                timeout=5
            )
            if resp.status_code == 200:
                for r in resp.json():
                    if r.get("status") != "fail":
                        result[r["query"]] = r
        except Exception:
            pass
    return result

