def send_slack(webhook_url, attack_type, severity, source_ip, confidence):
    if not webhook_url:
        return
    color = {"CRITICAL":"#FF2D55","HIGH":"#FF6B35","MEDIUM":"#F5A623"}.get(severity,"#00E5C0")
    try:
        requests.post(webhook_url, json={"attachments":[{
            "color": color,
            "title": f"[!] {severity} — {attack_type}",
            "text":  f"Source: `{source_ip}` · Confiance: {confidence*100:.1f}%\nTimestamp: {datetime.now().strftime('%H:%M:%S')}",
            "footer": "IDS Dashboard v3",
            "ts": int(time.time())
        }]}, timeout=3)
    except Exception:
        pass

def send_telegram(token: str, chat_id: str, attack_type, severity, source_ip, confidence):
    """Envoie une alerte Telegram. Fonctionne sur Android ET iPhone."""
    if not token or not chat_id:
        return
    try:
        sev_icon = {"CRITICAL":"🚨","HIGH":"⚠️","MEDIUM":"⚡","INFO":"ℹ️"}.get(severity,"🔔")
        now_str = datetime.now().strftime('%H:%M:%S')
        conf_str = f"{confidence*100:.1f}%"
        text = (
            f"{sev_icon} *IDS ALERTE* — {severity}\n"
            f"Type : {attack_type}\n"
            f"IP source : {source_ip}\n"
            f"Confiance : {conf_str}\n"
            f"Heure : {now_str}"
        )
        requests.post(
            f"https://api.telegram.org/bot{token}/sendMessage",
            json={"chat_id": chat_id, "text": text, "parse_mode": "Markdown"},
            timeout=5
        )
    except Exception:
        pass


def send_discord(webhook_url, attack_type, severity, source_ip, confidence):
    if not webhook_url:
        return
    color_map = {"CRITICAL":0xFF2D55,"HIGH":0xFF6B35,"MEDIUM":0xF5A623}
    try:
        requests.post(webhook_url, json={"embeds":[{
            "title":  f"[!] {severity} — {attack_type}",
            "color":  color_map.get(severity, 0x00E5C0),
            "fields": [
                {"name":"IP Source",  "value":source_ip,              "inline":True},
                {"name":"Confiance",  "value":f"{confidence*100:.1f}%","inline":True},
                {"name":"Heure",      "value":datetime.now().strftime('%H:%M:%S'),"inline":True},
            ],
            "footer": {"text":"IDS Dashboard v3"},
        }]}, timeout=3)
    except Exception:
        pass

def notify_attack(result):
    """Envoie une alerte si configuré et si l'attaque est CRITICAL ou HIGH."""
    if not result or not result.get("is_attack"):
        return
    sev = result.get("severity","")
    if sev not in ("CRITICAL","HIGH"):
        return
    cfg = st.session_state.get("notif_config", {})
    src = result.get("source_ip","N/A")
    conf = result.get("confidence", 0)
    atype = result.get("attack_type","Unknown")
    send_slack(cfg.get("slack",""), atype, sev, src, conf)
    send_discord(cfg.get("discord",""), atype, sev, src, conf)
    send_telegram(cfg.get("telegram_token",""), cfg.get("telegram_chat_id",""), atype, sev, src, conf)

# ================================================================
# HEURISTIQUES CLIENT-SIDE (amélioration #5)
# ================================================================

def apply_heuristics(df: pd.DataFrame) -> pd.DataFrame:
    """Détecte les attaques par règles sans passer par l'API."""
    df = df.copy()
    flags = pd.Series([""] * len(df), index=df.index)

    dur  = df.get("Flow Duration",    pd.Series(np.inf, index=df.index))
    fwd  = df.get("Total Fwd Packets",pd.Series(0,      index=df.index))
    bwd  = df.get("Total Backward Packets", pd.Series(0,index=df.index))
    bps  = df.get("Flow Bytes/s",     pd.Series(0,      index=df.index))
    pps  = df.get("Flow Packets/s",   pd.Series(0,      index=df.index))
    dport= df.get("Destination Port", pd.Series(0,      index=df.index))
    avg  = df.get("Average Packet Size",pd.Series(100,  index=df.index))
    iat  = df.get("Flow IAT Mean",    pd.Series(0,      index=df.index))

    # Port Scan : flux ultra-courts, 1-2 paquets, aucun backward
    port_scan = (dur < 2000) & (fwd <= 2) & (bwd == 0)
    flags[port_scan] = "PortScan"

    # DDoS : débit paquet très élevé
    ddos = (pps > 5000) & (flags == "")
    flags[ddos] = "DDoS"

    # DoS Hulk : débit octets élevé, flux courts
    hulk = (bps > 1_000_000) & (dur < 50_000) & (flags == "")
    flags[hulk] = "DoS Hulk"

    # Slowloris : longue durée, très faible débit, port 80
    slowloris = (dur > 200_000) & (bps < 200) & (dport == 80) & (flags == "")
    flags[slowloris] = "DoS slowloris"

    # SSH Brute Force : port 22, nombreux paquets, petits
    ssh_bf = (dport == 22) & (fwd > 15) & (avg < 60) & (flags == "")
    flags[ssh_bf] = "SSH-Patator"

    # FTP Brute Force : port 21
    ftp_bf = (dport == 21) & (fwd > 10) & (avg < 80) & (flags == "")
    flags[ftp_bf] = "FTP-Patator"

    # Bot : port 8080, IAT régulier (std faible), flux courts répétés
    bot = (dport == 8080) & (pps > 50) & (pps < 200) & (flags == "")
    flags[bot] = "Bot"

    df["heuristic_type"]  = flags
    df["heuristic_flag"]  = flags != ""
    return df

# ================================================================
# CORRÉLATION D'ALERTES (amélioration #6 / #20)
# ================================================================

def correlate_alerts(df_att: pd.DataFrame) -> pd.DataFrame:
    """Groupe les alertes par (source_ip, fenêtre 5 min). Retourne les incidents."""
    if df_att.empty or "source_ip" not in df_att.columns:
        return pd.DataFrame()
    df = df_att.copy()
    df["timestamp"] = pd.to_datetime(df["timestamp"], errors="coerce")
    df = df.dropna(subset=["timestamp"]).set_index("timestamp").sort_index()

    incidents = []
    for src_ip, grp in df.groupby("source_ip"):
        for ts, window in grp.resample("5min"):
            if window.empty:
                continue
            types  = window["attack_type"].unique().tolist() if "attack_type" in window.columns else []
            n_ev   = len(window)
            sev_w  = window["severity"].map(SEV_WEIGHT).max() if "severity" in window.columns else 1
            score  = min(int(n_ev * 8 + len(types) * 18 + (sev_w or 1) * 12), 100)
            incidents.append({
                "Timestamp":     ts.strftime("%Y-%m-%d %H:%M"),
                "IP Source":     src_ip,
                "Événements":    n_ev,
                "Types":         len(types),
                "Vecteurs":      ", ".join(types[:4]),
                "Sévérité max":  window["severity"].map(SEV_WEIGHT).idxmax()
                                  if "severity" in window.columns and not window.empty else "—",
                "Score risque":  score,
                "Multi-vecteur": len(types) >= 3,
            })
    if not incidents:
        return pd.DataFrame()
    return pd.DataFrame(incidents).sort_values("Score risque", ascending=False)

