def generate_synthetic_flows(attack_type, n=50):
    dist = ATTACK_DISTS.get(attack_type, ATTACK_DISTS["Trafic normal"])
    rows = []
    src_pool = [f"{random.randint(1,254)}.{random.randint(0,254)}.{random.randint(0,254)}.{random.randint(1,254)}" for _ in range(5)]
    for _ in range(n):
        row = {}
        for feat, (mu, sigma) in dist.items():
            if sigma == 0:
                row[feat] = float(mu)
            else:
                row[feat] = max(0.0, float(np.random.normal(mu, sigma)))
        row["source_ip"] = random.choice(src_pool)
        row["dest_ip"]   = f"10.0.0.{random.randint(1,5)}"
        row["protocol"]  = "TCP"
        rows.append(row)
    return pd.DataFrame(rows)

