def get_target_from_dest_ips(dest_ips):
    DEST_GEO = {
        "24.":"CA","47.":"CA","66.":"CA","70.":"CA","74.":"CA","96.":"CA","142.":"CA","162.":"CA",
        "3.":"US","4.":"US","8.":"US","12.":"US","13.":"US","34.":"US","35.":"US","52.":"US","54.":"US",
        "5.":"EU","31.":"EU","46.":"EU","77.":"EU","80.":"EU","185.":"EU","193.":"EU","212.":"EU",
    }
    REGION_COORDS = {
        "CA":{"lat":45.50,"lon":-73.57,"label":"Canada (Montréal)"},
        "US":{"lat":37.77,"lon":-122.41,"label":"États-Unis"},
        "EU":{"lat":48.85,"lon":  2.35,"label":"Europe"},
    }
    LOCAL = {"lat":45.50,"lon":-73.57,"label":"Réseau local"}
    counts = {}
    for ip in dest_ips:
        ip = str(ip)
        if ip.startswith(("10.","192.168.","172.16.","127.","0.")):
            counts["CA"] = counts.get("CA",0)+1; continue
        first = ip.split(".")[0]+"."
        r = DEST_GEO.get(first)
        if r: counts[r] = counts.get(r,0)+1
    if not counts: return LOCAL
    return REGION_COORDS.get(max(counts,key=counts.get), LOCAL)

