try:
    API_KEY = st.secrets["API_KEY"]
except Exception:
    API_KEY = os.environ.get("API_KEY", "")

@st.cache_data(ttl=2, show_spinner=False)
def call_api_cached(endpoint):
    """Version cachée de call_api pour les GET sans params dynamiques."""
    return call_api(endpoint)

def call_api(endpoint, method="GET", data=None, files=None, timeout=10):
    cached = cache_get(endpoint) if method == "GET" and files is None else None
    if cached is not None:
        return cached
    try:
        url     = f"{API_URL}{endpoint}"
        headers = {"X-API-Key": API_KEY} if API_KEY else {}
        if method == "GET":
            r = requests.get(url, headers=headers, timeout=timeout)
        elif method == "POST" and files:
            r = requests.post(url, headers=headers, files=files, timeout=timeout)
        elif method == "POST":
            r = requests.post(url, headers=headers, json=data, timeout=timeout)
        elif method == "DELETE":
            r = requests.delete(url, headers=headers, timeout=timeout)
        else:
            return None
        result = r.json() if r.status_code == 200 else None
        if result and method == "GET":
            cache_set(endpoint, result)
        return result
    except Exception:
        return None

def sev_tag(sev):
    return f'<span class="sev-tag tag-{sev.lower()}">{sev}</span>'

def alert_cls(sev):
    return {"CRITICAL":"alert-critical","HIGH":"alert-high","MEDIUM":"alert-medium","INFO":"alert-info"}.get(sev,"alert-info")

def pt():
    return dict(plot_bgcolor="rgba(0,0,0,0)", paper_bgcolor="rgba(0,0,0,0)",
                font=dict(color="#8BACC8", family="Calibri, sans-serif", size=11),
                margin=dict(l=0, r=0, t=8, b=0))

def cef_format(row) -> str:
    """Format Common Event Format (CEF) pour SIEM Splunk / QRadar."""
    ts  = str(row.get("timestamp",""))[:19].replace("T"," ")
    typ = str(row.get("attack_type","Unknown"))
    sev = {"CRITICAL":"10","HIGH":"8","MEDIUM":"5","INFO":"2"}.get(row.get("severity","INFO"),"5")
    src = row.get("source_ip","0.0.0.0")
    conf= int(float(row.get("confidence",0)) * 100)
    return (f"CEF:0|Anthropic|IDS-Dashboard|3.0|{typ.replace(' ','_')}|{typ}|{sev}|"
            f"src={src} sev={row.get('severity','INFO')} conf={conf} ts={ts}")

def process_csv_chunked(df, progress_bar, status_text):
    total, n_chunks = len(df), math.ceil(len(df)/CHUNK_SIZE)
    all_results, n_attacks, n_blocked, atk_types, errors = [], 0, 0, {}, 0
    thresholds = st.session_state.get("adaptive_thresholds", DEFAULT_THRESHOLDS)

    # Vérifier que l'API est disponible avant de lancer
    health = call_api("/health")
    if not health:
        st.error("API hors ligne. Lancez : uvicorn main_final:app --reload --port 8000")
        return None

    for i in range(n_chunks):
        chunk = df.iloc[i*CHUNK_SIZE:(i+1)*CHUNK_SIZE]
        buf   = io.BytesIO(); chunk.to_csv(buf, index=False); buf.seek(0)
        res   = call_api("/predict/batch", method="POST",
                         files={"file":(f"chunk_{i}.csv", buf, "text/csv")}, timeout=120)
        if res:
            # Appliquer seuils adaptatifs EN PREMIER avant de compter
            for r in res.get("results", []):
                thresh = thresholds.get(r.get("attack_type",""), thresholds.get("default",0.55))
                if r.get("confidence",0) < thresh:
                    r["is_attack"] = False
                    r["attack_type"] = "BENIGN"
                    r["severity"] = "INFO"
            all_results.extend(res.get("results",[]))
            # Recompter APRÈS filtrage (pas utiliser summary API qui ignore les seuils)
            for r in res.get("results", []):
                if r.get("is_attack", False):
                    n_attacks += 1
                    atype = r.get("attack_type","Unknown")
                    atk_types[atype] = atk_types.get(atype, 0) + 1
                if r.get("is_blocked", False):
                    n_blocked += 1
            # Notifications uniquement sur attaques confirmées après seuil
            for r in res.get("results",[]):
                if r.get("is_attack") and r.get("severity") in ("CRITICAL","HIGH"):
                    notify_attack(r)
        else:
            errors += 1
            if errors == 1:
                st.warning(f"Chunk {i+1} echoue. Verifiez que l'API tourne sur le port 8000.")
        progress_bar.progress((i+1)/n_chunks)
        done = min((i+1)*CHUNK_SIZE, total)
        status_text.markdown(
            f'<span style="font-family:\'Share Tech Mono\',monospace;font-size:0.77rem;color:#4D7FA8;">'
            f'Chunk {i+1}/{n_chunks} — {done:,}/{total:,} lignes · Erreurs : {errors}</span>',
            unsafe_allow_html=True)
    return {"summary":{"total_analyzed":total,"total_attacks":n_attacks,"total_blocked":n_blocked,
                       "attack_rate":round(n_attacks/max(total,1)*100,2),"attack_types":atk_types,"errors_chunks":errors},
            "results":all_results}

# ================================================================
# PARSE PCAP — Bidirectionnel + PcapReader streaming (amélioration #7)
# ================================================================

def parse_pcap(pcap_path, progress_cb=None):
    rows = []
    try:
        from scapy.all import IP, TCP, UDP
        # Amélioration #7 : PcapReader streaming pour gros fichiers
        try:
            from scapy.all import PcapReader
            pkt_iter = PcapReader(pcap_path)
            is_streaming = True
        except Exception:
            from scapy.all import rdpcap
            pkt_iter = rdpcap(pcap_path)
            is_streaming = False

        flows = {}
        idx   = 0
        for pkt in pkt_iter:
            idx += 1
            if progress_cb and idx % 500 == 0:
                progress_cb(min(idx / 50000 * 0.6, 0.58))
            if not pkt.haslayer(IP):
                continue
            proto = "TCP" if pkt.haslayer(TCP) else ("UDP" if pkt.haslayer(UDP) else None)
            if not proto:
                continue
            l4 = pkt[TCP] if proto == "TCP" else pkt[UDP]
            src_ip, dst_ip = pkt[IP].src, pkt[IP].dst
            sport, dport   = int(l4.sport), int(l4.dport)
            t, sz          = float(pkt.time), len(pkt)
            ep1, ep2       = (src_ip, sport), (dst_ip, dport)
            canonical      = (min(ep1,ep2), max(ep1,ep2), proto)

            if canonical not in flows:
                flows[canonical] = {
                    "fwd_ep":src_ip, "src_ip":src_ip, "dst_ip":dst_ip, "dport":dport, "proto":proto,
                    "start":t, "end":t,
                    "fwd_pkts":1, "fwd_bytes":sz, "fwd_sizes":[sz], "fwd_times":[t],
                    "fwd_win":getattr(l4,"window",-1) if proto=="TCP" else -1,
                    "bwd_pkts":0, "bwd_bytes":0, "bwd_sizes":[], "bwd_times":[], "bwd_win":-1,
                    "all_times":[t],
                }
            else:
                f = flows[canonical]
                f["end"] = t; f["all_times"].append(t)
                if src_ip == f["fwd_ep"]:
                    f["fwd_pkts"]+=1; f["fwd_bytes"]+=sz; f["fwd_sizes"].append(sz); f["fwd_times"].append(t)
                else:
                    f["bwd_pkts"]+=1; f["bwd_bytes"]+=sz; f["bwd_sizes"].append(sz); f["bwd_times"].append(t)
                    if f["bwd_win"]==-1 and proto=="TCP":
                        f["bwd_win"] = getattr(l4,"window",-1)

        n_flows = len(flows)
        for fi, f in enumerate(flows.values()):
            if progress_cb and fi % 100 == 0:
                progress_cb(0.6 + fi/max(n_flows,1)*0.4)
            dur      = max((f["end"]-f["start"])*1e6, 1.0)
            all_t    = sorted(f["all_times"])
            all_ia   = np.diff(all_t)*1e6 if len(all_t)>1 else np.array([0.0])
            all_sz   = f["fwd_sizes"] + (f["bwd_sizes"] if f["bwd_sizes"] else [])
            total_bytes = f["fwd_bytes"]+f["bwd_bytes"]
            total_pkts  = f["fwd_pkts"]+f["bwd_pkts"]
            rows.append({
                "Destination Port":        f["dport"],
                "Flow Duration":           dur,
                "Total Fwd Packets":       f["fwd_pkts"],
                "Total Backward Packets":  f["bwd_pkts"],
                "Flow Bytes/s":            total_bytes/(dur/1e6),
                "Flow Packets/s":          total_pkts/(dur/1e6),
                "Average Packet Size":     float(np.mean(all_sz)) if all_sz else 0.0,
                "Packet Length Mean":      float(np.mean(all_sz)) if all_sz else 0.0,
                "Init_Win_bytes_forward":  f["fwd_win"],
                "Init_Win_bytes_backward": f["bwd_win"],
                "Flow IAT Mean":           float(np.mean(all_ia)),
                "Flow IAT Std":            float(np.std(all_ia)) if len(all_ia)>1 else 0.0,
                "source_ip":               f["src_ip"],
                "dest_ip":                 f["dst_ip"],
                "protocol":                f["proto"],
            })
        return pd.DataFrame(rows)
    except ImportError:
        return pd.DataFrame()
    except Exception:
        return pd.DataFrame()

