def build_threat_map(country_counts, recent_attacks, target=None, local_attacks=None):
    """
    Map statique avec arcs animés en boucle via frames Plotly.
    Les attaques locales (IPs privées) génèrent un arc en boucle sur la cible.
    """
    import math as m
    fig = go.Figure()
    tgt = target or {"lat":45.50,"lon":-73.57,"label":"Réseau local"}
    local_attacks = local_attacks or []

    #  Choroplèthe fixe 
    if country_counts:
        df_c = pd.DataFrame([
            {"iso3":k,"name":GEO_COUNTRIES.get(k,{}).get("name",k),"count":v}
            for k,v in country_counts.items()
        ])
        fig.add_trace(go.Choropleth(
            locations=df_c["iso3"], z=df_c["count"], text=df_c["name"],
            colorscale=[[0,"#0B1120"],[0.15,"#0D1826"],[0.4,"#7B1515"],
                        [0.7,"#CC2020"],[1.0,"#FF2D55"]],
            autocolorscale=False,
            marker_line_color="#0D1826", marker_line_width=0.5,
            showscale=True,
            colorbar=dict(
                title=dict(text="Attaques", font=dict(color="#4D7FA8",size=10)),
                tickfont=dict(color="#4D7FA8",size=9),
                thickness=10, len=0.45,
                bgcolor="rgba(0,0,0,0)", bordercolor="#1C2B40"),
            hovertemplate="<b>%{text}</b><br>%{z} attaques<extra></extra>",
        ))

    #  Arcs animés smooth 
    arc_colors = {"CRITICAL":"#FF2D55","HIGH":"#FF6B35","MEDIUM":"#F5A623","INFO":"#00E5C0"}
    N_PTS   = 50   # points par arc
    N_STEPS = 50   # frames totales (25 croissance + 25 décroissance)

    arcs = []
    drawn = set()
    for atk in recent_attacks[:20]:
        iso3 = atk.get("iso3")
        if not iso3 or iso3 not in GEO_COUNTRIES or iso3 in drawn:
            continue
        drawn.add(iso3)
        geo = GEO_COUNTRIES[iso3]
        col = arc_colors.get(atk.get("severity","HIGH"), "#FF6B35")
        lats, lons = [], []
        for i in range(N_PTS + 1):
            t = i / N_PTS
            lat = tgt["lat"] + (geo["lat"] - tgt["lat"]) * t + m.sin(m.pi * t) * 5
            lon = tgt["lon"] + (geo["lon"] - tgt["lon"]) * t
            lats.append(lat); lons.append(lon)
        arcs.append({"lats":lats,"lons":lons,"col":col})

    # ── Arcs LOCAUX : boucle autour de la cible pour les IPs privées ──
    arc_colors_local = {"CRITICAL":"#FF2D55","HIGH":"#FF6B35","MEDIUM":"#F5A623","INFO":"#00E5C0"}
    drawn_local = set()
    for atk in local_attacks[:10]:
        src   = atk.get("source_ip","")
        sev   = atk.get("severity","HIGH")
        atype = atk.get("attack_type","")
        key   = f"{src}_{sev}"
        if key in drawn_local:
            continue
        drawn_local.add(key)
        col = arc_colors_local.get(sev, "#FF6B35")
        # Arc en boucle : part de la cible, fait un cercle de rayon variable, revient
        radius = 4 + (hash(src) % 5)  # rayon entre 4° et 9°
        angle_offset = (hash(src + "angle") % 360)
        lats, lons = [], []
        for i in range(N_PTS + 1):
            t = i / N_PTS
            angle = m.radians(angle_offset + 360 * t)
            # Ellipse autour de la cible
            lat = tgt["lat"] + radius * m.sin(angle) * 0.6
            lon = tgt["lon"] + radius * m.cos(angle)
            lats.append(lat); lons.append(lon)
        arcs.append({"lats":lats,"lons":lons,"col":col,"is_local":True,"label":f"{atype} ({src})"})

    # Marqueur pulsant rouge sur la cible si attaques locales détectées
    if local_attacks:
        max_sev = max(("CRITICAL" in [a["severity"] for a in local_attacks],
                       "HIGH"     in [a["severity"] for a in local_attacks],
                       "MEDIUM"   in [a["severity"] for a in local_attacks]), default=False)
        pulse_col = "#FF2D55" if any(a["severity"]=="CRITICAL" for a in local_attacks) else \
                    "#FF6B35" if any(a["severity"]=="HIGH"     for a in local_attacks) else "#F5A623"
        n_loc = len(local_attacks)
        # Anneau extérieur (alerte visuelle)
        fig.add_trace(go.Scattergeo(
            lon=[tgt["lon"]], lat=[tgt["lat"]], mode="markers",
            marker=dict(size=28, color="rgba(0,0,0,0)",
                        line=dict(color=pulse_col, width=3)),
            hovertemplate=f"<b>⚠ RÉSEAU LOCAL</b><br>{n_loc} attaque(s) interne(s)<extra></extra>",
            showlegend=False))
        # Anneau intermédiaire
        fig.add_trace(go.Scattergeo(
            lon=[tgt["lon"]], lat=[tgt["lat"]], mode="markers",
            marker=dict(size=18, color="rgba(0,0,0,0)",
                        line=dict(color=pulse_col, width=2)),
            hoverinfo="skip", showlegend=False))

    # Trace initiale pleine (visible dès le chargement)
    n_arc_traces = len(arcs)
    for arc in arcs:
        fig.add_trace(go.Scattergeo(
            lon=arc["lons"], lat=arc["lats"], mode="lines",
            line=dict(width=1.8, color=arc["col"]), opacity=0.7,
            showlegend=False, hoverinfo="skip"))

    # Frames : croissance puis décroissance des arcs
    frames = []
    half = N_STEPS // 2
    # Les traces arc commencent à l'index 1 (index 0 = choroplèthe)
    arc_start_idx = 1
    for step in range(N_STEPS + 1):
        progress = step / half if step <= half else 1.0 - (step - half) / half
        pts = max(2, int(progress * N_PTS))
        opacity = max(0.05, min(0.8, progress * 0.85))
        frame_data = []
        for i, arc in enumerate(arcs):
            frame_data.append(go.Scattergeo(
                lon=arc["lons"][:pts], lat=arc["lats"][:pts],
                mode="lines",
                line=dict(width=1.8, color=arc["col"]),
                opacity=opacity,
                showlegend=False, hoverinfo="skip"))
        frames.append(go.Frame(
            data=frame_data,
            traces=list(range(arc_start_idx, arc_start_idx + n_arc_traces)),
            name=str(step)))

    if frames:
        fig.frames = frames
        fig.update_layout(updatemenus=[dict(
            type="buttons", showactive=False, visible=False,
            buttons=[dict(
                label=">",
                method="animate",
                args=[None, {
                    "frame":       {"duration": 60, "redraw": False},
                    "fromcurrent": True,
                    "loop":        True,
                    "transition":  {"duration": 50, "easing": "linear"},
                }])])])

    #  Bulles sources 
    if country_counts:
        max_c = max(country_counts.values())
        for iso3, count in country_counts.items():
            geo = GEO_COUNTRIES.get(iso3)
            if not geo: continue
            r = 6 + (count / max_c) * 16
            fig.add_trace(go.Scattergeo(
                lon=[geo["lon"]], lat=[geo["lat"]], mode="markers",
                marker=dict(size=r, color="#FF2D55", opacity=0.85,
                            line=dict(color="#FF6B35", width=1.2)),
                hovertemplate=f"<b>{geo['name']}</b><br>{count} attaques<extra></extra>",
                showlegend=False))

    #  Cible (dernier = au-dessus) 
    fig.add_trace(go.Scattergeo(
        lon=[tgt["lon"]], lat=[tgt["lat"]],
        mode="markers+text",
        text=[tgt.get("label","Cible")], textposition="top center",
        textfont=dict(color="#00E5C0", size=10, family="Share Tech Mono"),
        marker=dict(size=15, color="#00E5C0", symbol="diamond",
                    line=dict(color="#007A60", width=2)),
        showlegend=False,
        hovertemplate="<b>Réseau cible</b><br>Destination des attaques<extra></extra>"))

    fig.update_geos(
        showframe=False, showcoastlines=True, coastlinecolor="#1A2B3C",
        showland=True,   landcolor="#0D1826",
        showocean=True,  oceancolor="#070B14",
        showlakes=False,
        showcountries=True, countrycolor="#1C2B40",
        bgcolor="#070B14", projection_type="natural earth")

    fig.update_layout(
        **pt(), geo=dict(bgcolor="#070B14"),
        height=500)
    return fig


def block_ip(ip: str) -> bool:
    """Tente de bloquer une IP via iptables. Retourne True si succès."""
    try:
        r = subprocess.run(
            ["iptables","-A","INPUT","-s",ip,"-j","DROP"],
            capture_output=True, timeout=3
        )
        return r.returncode == 0
    except Exception:
        return False

def unblock_ip(ip: str) -> bool:
    try:
        r = subprocess.run(
            ["iptables","-D","INPUT","-s",ip,"-j","DROP"],
            capture_output=True, timeout=3
        )
        return r.returncode == 0
    except Exception:
        return False

