            raw_type   = result.get("attack_type","")
            raw_conf   = result.get("confidence", 0)
            # Chercher le seuil sur le type brut retourné par l'API (avant override)
            thresh = thresholds.get(raw_type, thresholds.get("default", 0.55))
            # Appliquer le seuil : si confiance < seuil → forcer BENIGN
            if raw_conf < thresh:
                result["is_attack"]   = False
                result["attack_type"] = "BENIGN"
                result["severity"]    = "INFO"

