        if csv_file:
            with st.spinner("Lecture..."):
                try:
                    df_full = pd.read_csv(csv_file, low_memory=False)
                except Exception as e:
                    st.error(f"Erreur de lecture : {e}"); st.stop()

            # ----------------------------------------------------------------
            # Mapping automatique des colonnes CIC-IDS2017
            # Supporte les CSV originaux à 79 colonnes (noms avec espaces en tête)
            # ----------------------------------------------------------------
            df_full.columns = df_full.columns.str.strip()

            # Table de correspondance noms CIC-IDS2017 → noms attendus par l'API
            _COL_ALIASES = {
                "Destination Port":        ["Destination Port", "Dst Port", "dst_port"],
                "Flow Duration":           ["Flow Duration", "flow_duration"],
                "Total Fwd Packets":       ["Total Fwd Packets", "Tot Fwd Pkts", "total_fwd_packets"],
                "Total Backward Packets":  ["Total Backward Packets", "Tot Bwd Pkts", "total_bwd_packets"],
                "Flow Bytes/s":            ["Flow Bytes/s", "Flow Byts/s", "flow_bytes_s"],
                "Flow Packets/s":          ["Flow Packets/s", "Flow Pkts/s", "flow_pkts_s"],
                "Average Packet Size":     ["Average Packet Size", "Avg Pkt Size", "average_packet_size"],
                "Packet Length Mean":      ["Packet Length Mean", "Pkt Len Mean", "pkt_len_mean"],
                "Init_Win_bytes_forward":  ["Init_Win_bytes_forward", "Init Fwd Win Byts", "init_win_bytes_forward"],
                "Init_Win_bytes_backward": ["Init_Win_bytes_backward", "Init Bwd Win Byts", "init_win_bytes_backward"],
                "Flow IAT Mean":           ["Flow IAT Mean", "flow_iat_mean"],
                "Flow IAT Std":            ["Flow IAT Std", "Flow IAT Std.", "flow_iat_std"],
            }
            _renames = {}
            for canonical, aliases in _COL_ALIASES.items():
                if canonical in df_full.columns:
                    continue  # déjà bon
                for alias in aliases:
                    if alias in df_full.columns:
                        _renames[alias] = canonical
                        break
            if _renames:
                df_full = df_full.rename(columns=_renames)

            # Vérifier les colonnes manquantes APRÈS mapping
            _required = list(_COL_ALIASES.keys())
            _missing  = [c for c in _required if c not in df_full.columns]
            if _missing:
                st.warning(f"[WARN] Colonnes introuvables après mapping automatique : {_missing}\n\nColonnes présentes : {list(df_full.columns[:15])}...")
            else:
                if len(df_full.columns) > len(_required):
                    st.success(f"[OK] CSV à {len(df_full.columns)} colonnes détecté — {len(_renames)} colonnes remappées automatiquement vers le format CIC-IDS2017.")

            # Amélioration #5 — Heuristiques immédiates
            df_full = apply_heuristics(df_full)
            n_heur  = df_full["heuristic_flag"].sum() if "heuristic_flag" in df_full.columns else 0

            c1,c2,c3,c4 = st.columns(4)
            c1.metric("Lignes",        f"{len(df_full):,}")
            c2.metric("Colonnes",      f"{len(df_full.columns)}")
            c3.metric("Chunks",        f"{math.ceil(len(df_full)/CHUNK_SIZE)}")
            c4.metric("Suspects (heuristique)", f"{n_heur:,}")

            if n_heur > 0:
                heur_types = df_full[df_full["heuristic_flag"]]["heuristic_type"].value_counts()
                st.markdown('<div class="info-box"><strong style="color:#F5A623;">Détections heuristiques (sans API)</strong> : '
                            + " · ".join([f"<strong>{t}</strong> ({c})" for t,c in heur_types.items()])
                            + "</div>", unsafe_allow_html=True)

            st.dataframe(df_full.head(5), width='stretch')


            # Verifier API avant affichage du bouton
            _api_up = call_api("/health") is not None
            if not _api_up:
                st.error("API hors ligne. Lancez : uvicorn main_final:app --reload --port 8000")
            if _api_up and st.button("Lancer l'analyse CSV", width='stretch', key="btn_csv"):
                    df_api = df_full.drop(columns=["heuristic_type","heuristic_flag"], errors="ignore")
                    pb = st.progress(0.0); stx = st.empty(); t0 = time.time()
                    res = process_csv_chunked(df_api, pb, stx)
                    elapsed = time.time()-t0
                    pb.progress(1.0)
                    stx.markdown(f'<span style="font-family:Share Tech Mono,monospace;font-size:0.77rem;color:#00E5C0;">Termine en {elapsed:.1f}s</span>', unsafe_allow_html=True)
                    if res:
                        s = res["summary"]
                        r1,r2,r3,r4 = st.columns(4)
                        r1.metric("Flux analyses",  f"{s.get('total_analyzed',0):,}")
                        r2.metric("Attaques",        f"{s.get('total_attacks',0):,}", delta=f"{s.get('attack_rate',0)}%", delta_color="inverse")
                        r3.metric("Bloques",         f"{s.get('total_blocked',0):,}")
                        r4.metric("Sains",           f"{s['total_analyzed']-s.get('total_attacks',0):,}")
                        if s["attack_types"]:
                            df_at = pd.DataFrame(list(s["attack_types"].items()), columns=["Type","N"]).sort_values("N",ascending=False)
                            fig   = px.bar(df_at, x="Type", y="N", color="N", color_continuous_scale=[[0,"#1C2B40"],[1,"#FF2D55"]])
                            fig.update_layout(**pt(), showlegend=False, coloraxis_showscale=False, xaxis_tickangle=40, height=280)
                            fig.update_traces(marker_line_width=0)
                            st.plotly_chart(fig, use_container_width=True)
                        if res["results"]:
                            df_r  = pd.DataFrame(res["results"])
                            cols_r = [col for col in ["timestamp","attack_type","severity","confidence","blocked","source_ip","dest_ip"] if col in df_r.columns]
                            df_r  = df_r[cols_r].copy()
