            fig_tc = px.bar(tc.sort_values("N"),x="N",y="Type",orientation="h",color="N",
                            color_continuous_scale=[[0,"#1C2B40"],[0.5,"#FF6B35"],[1,"#FF2D55"]])
            fig_tc.update_layout(**pt(),height=300,coloraxis_showscale=False)
