    with s2: st.markdown(f'<div class="kpi-card" style="border-top-color:#FF2D55;"><div class="kpi-label">Attaques</div><div class="kpi-value">{n_att2:,}</div><div class="kpi-sub" style="color:#FF2D55;">{n_att2/max(n_total,1)*100:.1f}%</div></div>', unsafe_allow_html=True)
    with s3: st.markdown(f'<div class="kpi-card" style="border-top-color:#F5A623;"><div class="kpi-label">Bloqués</div><div class="kpi-value">{n_blk:,}</div></div>', unsafe_allow_html=True)
    with s4: st.markdown(f'<div class="kpi-card" style="border-top-color:#00E5C0;"><div class="kpi-label">Confiance moy.</div><div class="kpi-value">{avg_c*100:.1f}<span style="font-size:1rem">%</span></div></div>', unsafe_allow_html=True)

