        for i in range(int(sim_n)):
            # Bruiter les features numériques
            noisy = {}
            noise_factor = sim_noise / 100.0
            for k, v in base_params.items():
                if isinstance(v, float) and v > 0:
                    noisy[k] = round(v * (1 + _rand.uniform(-noise_factor, noise_factor)), 4)
                else:
                    noisy[k] = v
