        sevs   = ["CRITICAL","HIGH","HIGH","MEDIUM","INFO"]
        base   = datetime.now()-timedelta(hours=12)
        # Simuler 3 attaquants distincts avec patterns différents
        rows = []
        attackers = [
            f"45.{random.randint(1,254)}.{random.randint(1,254)}.{random.randint(1,254)}",
            f"91.{random.randint(1,254)}.{random.randint(1,254)}.{random.randint(1,254)}",
            f"185.{random.randint(1,254)}.{random.randint(1,254)}.{random.randint(1,254)}",
        ]
        for att in attackers:
            n_events = random.randint(20,80)
            for _ in range(n_events):
                t = base+timedelta(minutes=random.uniform(0,720))
                rows.append({"timestamp":t.isoformat(),"attack_type":random.choice(atypes),
                             "severity":random.choices(sevs,[0.2,0.35,0.3,0.1,0.05])[0],
                             "is_attack":True,"confidence":round(random.uniform(0.65,0.99),3),
                             "blocked":random.random()>0.4,"source_ip":att,
                             "dest_ip":random.choice(["10.0.0.1","10.0.0.2","192.168.1.10"])})
