        k2.metric("Score max",          f"{max_score}/100")
        k3.metric("Incidents critiques (≥70)", f"{n_critical_inc:,}")
        k4.metric("Multi-vecteurs (≥3 types)", f"{n_multivec:,}")

        # Scatter incidents : score vs n_events
        st.markdown('<div class="section-title">Carte des incidents — risque vs volume</div>', unsafe_allow_html=True)
        df_inc_plot = df_incidents.head(50).copy()
