        fig_sc = px.scatter(df_inc_plot, x="Événements", y="Score risque",
                            color="Criticité", size="Types",
                            color_discrete_map={"Critique":"#FF2D55","Élevé":"#FF6B35","Modéré":"#F5A623"},
                            hover_data=["IP Source","Vecteurs"],
                            labels={"Événements":"Nombre d'alertes","Score risque":"Score de risque (0-100)"})
        fig_sc.update_layout(**pt(), height=360,
            xaxis=dict(showgrid=True,gridcolor="#1C2B40",tickfont=dict(color="#4D7FA8",size=10)),
            yaxis=dict(showgrid=True,gridcolor="#1C2B40",tickfont=dict(color="#4D7FA8",size=10)),
            legend=dict(font=dict(color="#8BACC8")))
        fig_sc.update_traces(marker=dict(line=dict(width=0)))
        st.plotly_chart(fig_sc, use_container_width=True)

        # Top incidents
        st.markdown('<div class="section-title">Top incidents (score de risque décroissant)</div>', unsafe_allow_html=True)
        for _, inc in df_incidents.head(10).iterrows():
            score      = inc["Score risque"]
            mv         = inc.get("Multi-vecteur", False)
            border_cls = "incident-critical" if score >= 70 else ""
            score_col  = "#FF2D55" if score >= 70 else "#F5A623"

            mv_badge = (
                '<span style="background:rgba(245,166,35,0.18);color:#F5A623;'
                'border-radius:3px;padding:1px 6px;font-size:0.65rem;font-weight:700;margin-left:6px;">'
                'MULTI-VECTEUR</span>'
            ) if mv else ""

            bar_html = (
                '<div style="height:3px;background:#1C2B40;border-radius:2px;margin-top:8px;">'
                f'<div style="height:100%;width:{score}%;background:{score_col};border-radius:2px;"></div>'
                '</div>'
            )

            card_html = (
                f'<div class="incident-card {border_cls}">'
                '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">'
                f'<span style="font-family:Share Tech Mono,monospace;font-size:0.85rem;color:#FF6B35;font-weight:700;">{inc["IP Source"]}</span>'
                f'{mv_badge}'
                f'<span style="font-family:Share Tech Mono,monospace;font-size:1.1rem;color:{score_col};font-weight:700;">{score}/100</span>'
                '</div>'
                '<div style="font-size:0.76rem;color:#8BACC8;">'
                f' {inc["Timestamp"]} &nbsp;·&nbsp; {inc["Événements"]} alertes &nbsp;·&nbsp; '
                f'{inc["Types"]} types &nbsp;·&nbsp; Sévérité max : '
                f'<strong style="color:#E8F4FF;">{inc["Sévérité max"]}</strong>'
                '</div>'
                f'<div style="font-family:Share Tech Mono,monospace;font-size:0.69rem;color:#4D7FA8;margin-top:4px;">{inc["Vecteurs"]}</div>'
                f'{bar_html}'
                '</div>'
            )
            st.markdown(card_html, unsafe_allow_html=True)

        #  Fingerprinting d'attaquant (#4) 
        st.markdown('<div class="section-title">Fingerprinting attaquant</div>', unsafe_allow_html=True)
        if "source_ip" in df_corr.columns and "attack_type" in df_corr.columns:
            fp_groups = df_corr.groupby("source_ip")["attack_type"].apply(list).reset_index()
            fp_groups.columns = ["IP","Types"]
            fp_groups["Signature"] = fp_groups["Types"].apply(lambda x: ",".join(sorted(set(x))))
            dup_sigs = fp_groups[fp_groups.duplicated("Signature", keep=False)]
            if not dup_sigs.empty:
                st.warning(f"[WARN] {dup_sigs['Signature'].nunique()} signature(s) d'attaque identique(s) detectee(s) sur des IPs differentes — probable meme attaquant.")
                for sig, grp in dup_sigs.groupby("Signature"):
                    ips_match = grp["IP"].tolist()
                    st.markdown(f'<div class="incident-card"><div style="color:#F5A623;font-size:0.78rem;font-weight:700;">Signature : {sig[:60]}</div><div style="font-family:Share Tech Mono,monospace;font-size:0.72rem;color:#8BACC8;margin-top:4px;">IPs : {" · ".join(ips_match[:5])}</div></div>', unsafe_allow_html=True)
            else:
                st.success("Aucun fingerprint similaire detecte entre les IPs.")

        #  Prédiction prochaine attaque (#5) 
        st.markdown('<div class="section-title">Prediction — Prochaine attaque probable</div>', unsafe_allow_html=True)
        if "attack_type" in df_corr.columns and len(df_corr) >= 10:
            recent_types = df_corr.sort_values("timestamp").tail(20)["attack_type"].tolist() if "timestamp" in df_corr.columns else df_corr["attack_type"].tail(20).tolist()
            type_counts  = pd.Series(recent_types).value_counts()
            total_recent = len(recent_types)
            predictions  = [(t, round(n/total_recent*100,1)) for t,n in type_counts.items()]
            predictions.sort(key=lambda x:-x[1])
            col_p1, col_p2 = st.columns(2)
            for i, (atype, prob) in enumerate(predictions[:4]):
                col = col_p1 if i%2==0 else col_p2
                sev_p = {"DDoS":"CRITICAL","Infiltration":"CRITICAL","Heartbleed":"CRITICAL","SSH-Patator":"HIGH","FTP-Patator":"HIGH","Bot":"HIGH","PortScan":"MEDIUM"}.get(atype,"MEDIUM")
                c_p = {"CRITICAL":"#FF2D55","HIGH":"#FF6B35","MEDIUM":"#F5A623"}.get(sev_p,"#8BACC8")
                col.markdown(f'<div class="kpi-card" style="border-top-color:{c_p};margin-bottom:8px;"><div class="kpi-label">{atype[:25]}</div><div class="kpi-value" style="font-size:1.6rem;color:{c_p};">{prob:.0f}%</div><div class="kpi-sub" style="color:{c_p};">probabilite basee sur historique recent</div></div>', unsafe_allow_html=True)

        # Export
        st.markdown("---")
        st.download_button("Exporter incidents CSV", df_incidents.to_csv(index=False),
                           f"incidents_{datetime.now().strftime('%Y%m%d_%H%M%S')}.csv","text/csv", width='stretch')

