        df_vol["confidence"] = pd.to_numeric(df_vol["confidence"], errors="coerce").fillna(0)

        # Estimation des octets : basé sur la sévérité (approximation réaliste)
        SEV_BYTES = {"CRITICAL": 150000, "HIGH": 45000, "MEDIUM": 8000, "INFO": 500}
        df_vol["bytes_est"] = df_vol["severity"].map(SEV_BYTES).fillna(1000)
        df_vol["mb_est"]    = df_vol["bytes_est"] / 1_000_000

        total_gb  = df_vol["bytes_est"].sum() / 1e9
        attack_gb = df_vol[df_vol["is_attack"]==True]["bytes_est"].sum() / 1e9 if "is_attack" in df_vol.columns else 0

        # KPIs
        k1,k2,k3,k4 = st.columns(4)
        k1.metric("Volume total estimé",    f"{total_gb:.2f} GB")
        k2.metric("Volume malveillant",     f"{attack_gb:.2f} GB")
        k3.metric("% trafic malveillant",   f"{attack_gb/max(total_gb,0.001)*100:.1f}%")
        k4.metric("Flux analysés",          f"{len(df_vol):,}")

        # Volume par type d'attaque
        st.markdown('<div class="section-title">Volume estimé par type d\'attaque</div>', unsafe_allow_html=True)
