            fig_ip = px.bar(df_ip_vol, x="Volume (MB)", y="IP", orientation="h",
                color="Volume (MB)",
                color_continuous_scale=[[0,"#1C2B40"],[1,"#FF2D55"]])
            fig_ip.update_layout(**pt(), height=300, coloraxis_showscale=False,
                xaxis=dict(showgrid=True,gridcolor="#1C2B40",tickfont=dict(color="#4D7FA8",size=10)),
                yaxis=dict(tickfont=dict(color="#C8D6E5",size=11)))
